    26→
    27→// ---------------------------------------------------------------------------
    28→// Constants
    29→// ---------------------------------------------------------------------------
    30→
    31→const NAV_ITEMS = [
    32→  { label: "Sessions",     path: "/",                     sym: "≡"  },
    33→  { label: "Session Tree", path: "/session-tree",         sym: "⬡"  },
    34→  { label: "Checkpoints",  path: "/checkpoints",          sym: "⬛" },
    35→  { label: "Timeline",     path: "/checkpoints/timeline", sym: "◎"  },
    36→  { label: "Repos",        path: "/repos",                sym: "⊡"  },
    37→] as const;
    38→
    39→const TOP_LEVEL = new Set(["/", "/session-tree", "/checkpoints", "/checkpoints/timeline", "/repos"]);
    40→
    41→function getActiveNav(pathname: string): string {
    42→  if (pathname === "/" || pathname.startsWith("/sessions/")) return "/";
    43→  if (pathname === "/session-tree") return "/session-tree";
    44→  if (pathname === "/checkpoints/timeline") return "/checkpoints/timeline";
    45→  if (pathname.startsWith("/checkpoints")) return "/checkpoints";
    46→  if (pathname === "/repos") return "/repos";
    47→  return "";
    48→}
    49→
    50→// ---------------------------------------------------------------------------
    51→// Branch selector (for branchLog tabs shown in the header)
    52→// ---------------------------------------------------------------------------
    53→
    54→function BranchSelector({
    55→  localPath,
    56→  branch,
    57→  repoName,
