    88→    />
    89→  );
    90→}
    91→
    92→// ---------------------------------------------------------------------------
    93→// Home tab — its own MemoryRouter, registers navigate with TabsContext
    94→// ---------------------------------------------------------------------------
    95→
    96→/** Registers/unregisters the home router's navigate with TabsContext and syncs pathname. */
    97→function HomeTabBridge() {
    98→  const navigate = useNavigate();
    99→  const { pathname } = useLocation();
   100→  const { registerHomeNavigate, updateHomePathname } = useTabs();
   101→
   102→  useEffect(() => {
   103→    registerHomeNavigate(navigate as (to: string | number) => void);
   104→    return () => registerHomeNavigate(null);
   105→  }, [navigate, registerHomeNavigate]);
   106→
   107→  useEffect(() => {
   108→    updateHomePathname(pathname);
   109→  }, [pathname, updateHomePathname]);
   110→
   111→  return <Outlet />;
   112→}
   113→
   114→function HomeTab() {
