useEffect(() => {
  if (!session?.isLive) return;
  const timer = setInterval(() => {
    Promise.all([fetchLogEvents(id), fetchSessionCheckpoints(id)])
      .then(([logEvs, cps]) => {
        logEventsRef.current = logEvs;
        applyData(logEvs, cps);
      })
      .catch(() => undefined);
  }, 500);
  return () => clearInterval(timer);
}, [id, session?.isLive]);

